</span>);\n    <span class=\"dc\">o</span>.<span class=\"fn\">SetState</span>(<span class=\"kw\">new</span> <span class=\"cl\">Paid</span>());\n  }\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">Order</span> {\n  <span class=\"cl\">IState</span> <span class=\"dc\">_state</span> = <span class=\"kw\">new</span> <span class=\"cl\">Pending</span>();\n  <span class=\"kw\">public void</span> <span class=\"fn\">SetState</span>(<span class=\"cl\">IState</span> <span class=\"dc\">s</span>) =&gt; <span class=\"dc\">_state</span> = <span class=\"dc\">s</span>;\n  <span class=\"kw\">public void</span> <span class=\"fn\">Advance</span>() =&gt; <span class=\"dc\">_state</span>.<span class=\"fn\">Next</span>(<span class=\"dc\">this</span>);\n}", "Python": "<span class=\"kw\">class</span> <span class=\"cl\">Order</span>:\n  <span class=\"dc\">TRANSITIONS</span> = {\n    <span class=\"st\">\"pending\"</span>: <span class=\"st\">\"paid\"</span>,\n    <span class=\"st\">\"paid\"</span>:    <span class=\"st\">\"shipped\"</span>,\n    <span class=\"st\">\"shipped\"</span>: <span class=\"st\">\"delivered\"</span>\n  }\n\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>): <span class=\"dc\">self.state</span> = <span class=\"st\">\"pending\"</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">advance</span>(<span class=\"dc\">self</span>):\n    <span class=\"dc\">prev</span> = <span class=\"dc\">self.state</span>\n    <span class=\"dc\">self.state</span> = <span class=\"dc\">self</span>.<span class=\"dc\">TRANSITIONS</span>.<span class=\"fn\">get</span>(<span class=\"dc\">self.state</span>, <span class=\"dc\">self.state</span>)\n    <span class=\"fn\">print</span>(<span class=\"st\">f\"{{prev}} \u2192 {{self.state}}\"</span>)", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">Order</span>\n  <span class=\"dc\">TRANS</span> = {\n    <span class=\"dc\">pending:</span> <span class=\"st\">:paid</span>, <span class=\"dc\">paid:</span> <span class=\"st\">:shipped</span>, <span class=\"dc\">shipped:</span> <span class=\"st\">:delivered</span>\n  }\n\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span> = <span class=\"dc\">@s</span> = <span class=\"st\">:pending</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">advance</span>\n    <span class=\"dc\">n</span> = <span class=\"dc\">TRANS</span>[<span class=\"dc\">@s</span>] || <span class=\"dc\">@s</span>\n    <span class=\"fn\">puts</span> <span class=\"st\">\"#{{@s}} \u2192 #{{n}}\"</span>; <span class=\"dc\">@s</span> = <span class=\"dc\">n</span>\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>"}

